module.sampleData:
[{
    "match_id": "sample-match-001",
    "event_id": "sample-match-001",
    "clock": {"minute": 78, "stoppage": 2, "period": "2H"},
    "score": {"home": 1, "away": 1},
    "teams": {
        "home": {"name": "Home FC", "abbreviation": "HME", "logo_url": ""},
        "away": {"name": "Away FC", "abbreviation": "AWY", "logo_url": ""}
    },
    "excitement": {"level": 0.82, "trend": "rising"},
    "last_moment": {
        "type": "goal",
        "team": "home",
        "minute": 78,
        "text": "Goal! Home FC equalise in the 78th minute — stadium erupts."
    },
    "next_update_hint_ms": 500
}]

module.onRender:
// Module renderer options
// id: The id of the widget
// target: The target element to render
// items: Preview / cached payload (phase-1 expects length 1 in preview mode)
// properties: The properties for the widget

(function () {
    'use strict';

    var $target = (typeof $ === 'function') ? $(target) : null;
    var $root = $target ? $target.find('[data-crowdaq-root]') : null;
    if (!$root || $root.length === 0) { return; }
    var rootEl = $root.get(0);

    var props = properties || {};
    var refreshInterval = parseInt(props.refreshInterval, 10);
    if (isNaN(refreshInterval) || refreshInterval < 5) { refreshInterval = 30; }
    var showTeamLogos = !!props.showTeamLogos;
    var showLastMoment = !!props.showLastMoment;
    var maxMomentLength = parseInt(props.maxMomentLength, 10);
    if (isNaN(maxMomentLength) || maxMomentLength <= 0) { maxMomentLength = 80; }

    // Resolve the API base URL: explicit property first, then the
    // bar-player bootstrap global. Per-widget settings win so an
    // operator can point a single bar at a different backend.
    var apiBaseUrlRaw = (typeof props.apiBaseUrl === 'string' ? props.apiBaseUrl : '').trim();
    var eventIdRaw = (typeof props.eventId === 'string' ? props.eventId : '').trim();

    // Multi-bar targeting: values of the form "display:<field>" are
    // resolved at render time against the player's xiboIC.info()
    // response. Supported fields (4.4.2): hardwareKey, displayName,
    // timeZone, latitude, longitude. See docs/TARGETING.md.
    // Xibo 4.4.2 does NOT expose the display's tag list to widgets
    // (xiboIC has no getDisplayTags and /info does not return tags —
    // see xibosignage/xibo-interactive-control README); the stable
    // primitive operators get is displayName. Encode the CROWDAQ event
    // id in displayName when you want one layout to serve many bars.
    var DISPLAY_FIELD_ALLOWLIST = {
        hardwareKey: 1,
        displayName: 1,
        timeZone: 1,
        latitude: 1,
        longitude: 1
    };
    var DISPLAY_PREFIX = 'display:';
    function needsDisplayResolution(value) {
        return typeof value === 'string' && value.indexOf(DISPLAY_PREFIX) === 0;
    }
    function parseDisplayField(value) {
        return value.slice(DISPLAY_PREFIX.length);
    }
    function resolveFromInfo(value, info) {
        if (!needsDisplayResolution(value)) { return value; }
        var field = parseDisplayField(value);
        if (!DISPLAY_FIELD_ALLOWLIST[field]) { return ''; }
        if (!info || typeof info !== 'object') { return ''; }
        var raw = info[field];
        if (raw == null) { return ''; }
        return String(raw);
    }

    // --- DOM helpers: selectors are data-attr based so Twig can rename
    //     classes without breaking the JS. ---
    function q(sel) { return rootEl.querySelector(sel); }
    function setText(sel, text) {
        var el = q(sel);
        if (el) { el.textContent = (text == null ? '' : String(text)); }
    }
    function setAttr(sel, attr, value) {
        var el = q(sel);
        if (el) { el.setAttribute(attr, value); }
    }
    function show(sel, visible) {
        var el = q(sel);
        if (!el) { return; }
        if (visible) { el.removeAttribute('hidden'); }
        else { el.setAttribute('hidden', ''); }
    }
    function truncate(text, maxLen) {
        if (typeof text !== 'string') { return ''; }
        if (text.length <= maxLen) { return text; }
        return text.slice(0, maxLen - 1) + '…';
    }

    // --- Status pill + error pill + stale overlay + lifecycle banner ---
    function setStatus(state, label) {
        setAttr('[data-crowdaq-status]', 'data-state', state);
        setText('[data-crowdaq-status]', label || state);
    }
    function showErrorPill(message) {
        var el = q('[data-crowdaq-error-pill]');
        if (!el) { return; }
        if (!message) {
            el.setAttribute('hidden', '');
            el.textContent = '';
            return;
        }
        el.textContent = message;
        el.removeAttribute('hidden');
    }
    function showStale(isStale) {
        if (isStale) { rootEl.classList.add('crowdaq-stale'); }
        else { rootEl.classList.remove('crowdaq-stale'); }
        show('[data-crowdaq-stale-overlay]', isStale);
    }
    function showLifecycleBanner(label) {
        show('[data-crowdaq-status-overlay]', !!label);
        setText('[data-crowdaq-status-overlay-text]', label || '');
    }

    // --- Team-logo handling with abbreviation fallback ---
    function setTeamLogo(selector, nameSelector, src, nameText, abbreviation) {
        var img = q(selector);
        if (!img) { return; }
        if (!showTeamLogos || !src) {
            img.setAttribute('hidden', '');
            img.removeAttribute('src');
            // Fallback to abbreviation when logos are disabled OR no url.
            setText(nameSelector, abbreviation || nameText || '');
            return;
        }
        img.onerror = function () {
            img.setAttribute('hidden', '');
            setText(nameSelector, abbreviation || nameText || '');
        };
        img.setAttribute('alt', nameText || '');
        img.setAttribute('src', src);
        img.removeAttribute('hidden');
        setText(nameSelector, abbreviation || nameText || '');
    }

    // --- score-update handler: full snapshot -> DOM ---
    var lastScore = { home: null, away: null };
    function onScoreUpdate(payload) {
        if (!payload || typeof payload !== 'object') { return; }
        var teams = payload.teams || {};
        var score = payload.score || {};
        var excitement = payload.excitement || {};
        var lastMoment = payload.last_moment || {};

        var homeTeam = teams.home || {};
        var awayTeam = teams.away || {};

        setTeamLogo(
            '[data-crowdaq-team-a-logo]',
            '[data-crowdaq-team-a]',
            homeTeam.logo_url,
            homeTeam.name,
            homeTeam.abbreviation
        );
        setTeamLogo(
            '[data-crowdaq-team-b-logo]',
            '[data-crowdaq-team-b]',
            awayTeam.logo_url,
            awayTeam.name,
            awayTeam.abbreviation
        );

        // deltaSinceLast flash for score changes.
        var newHome = (score.home != null) ? score.home : 0;
        var newAway = (score.away != null) ? score.away : 0;
        if (lastScore.home !== null && newHome > lastScore.home) {
            flash('[data-crowdaq-team-a-score]');
        }
        if (lastScore.away !== null && newAway > lastScore.away) {
            flash('[data-crowdaq-team-b-score]');
        }
        lastScore.home = newHome;
        lastScore.away = newAway;
        setText('[data-crowdaq-team-a-score]', newHome);
        setText('[data-crowdaq-team-b-score]', newAway);

        // Excitement meter (level is 0..1 per contract).
        var level = parseFloat(excitement.level);
        if (isNaN(level)) { level = 0; }
        var clamped = Math.max(0, Math.min(1, level));
        var meterEl = q('[data-crowdaq-excitement-fill]');
        if (meterEl) { meterEl.style.width = (clamped * 100) + '%'; }
        setText('[data-crowdaq-excitement-value]', (clamped * 10).toFixed(1));
        setAttr('[data-crowdaq-excitement]', 'aria-valuenow', (clamped * 10).toFixed(1));
        var trend = excitement.trend || 'flat';
        var trendEl = q('[data-crowdaq-excitement-trend]');
        if (trendEl) {
            trendEl.setAttribute('data-trend', trend);
            trendEl.innerHTML = (trend === 'rising')
                ? '&#9650;'
                : (trend === 'falling' ? '&#9660;' : '&bull;');
        }

        // Last moment row — score-update carries the current summary.
        if (showLastMoment && lastMoment && typeof lastMoment.text === 'string') {
            setText('[data-crowdaq-moment-text]', truncate(lastMoment.text, maxMomentLength));
        }
    }
    function flash(selector) {
        var el = q(selector);
        if (!el) { return; }
        el.classList.add('crowdaq-delta-flash');
        setTimeout(function () {
            if (el && el.classList) { el.classList.remove('crowdaq-delta-flash'); }
        }, 600);
    }

    // --- moment handler: standalone notable-moment text line ---
    function onMoment(payload) {
        if (!showLastMoment || !payload || typeof payload.description !== 'string') {
            return;
        }
        setText('[data-crowdaq-moment-text]', truncate(payload.description, maxMomentLength));
    }

    // --- status handler: lifecycle state banner ---
    function onStatus(payload) {
        if (!payload || typeof payload.state !== 'string') { return; }
        var state = payload.state;
        var label = '';
        switch (state) {
            case 'pre_game':         label = 'pre-game'; break;
            case 'halftime':         label = 'halftime'; break;
            case 'extra_time':       label = 'extra time'; break;
            case 'penalty_shootout': label = 'penalties'; break;
            case 'final':            label = 'final'; break;
            case 'cancelled':        label = 'cancelled'; break;
            case 'postponed':        label = 'postponed'; break;
            case 'live':             label = ''; break;  // no banner when live
            default:                 label = state;
        }
        showLifecycleBanner(label);
    }

    // --- heartbeat handler: reset stale indicator only ---
    function onHeartbeat() {
        // Handled uniformly by resetStaleTimer() in the SSE dispatcher.
    }

    // --- error handler: show error pill + trigger reconnect ---
    function onStreamError(payload) {
        var msg = (payload && typeof payload.message === 'string')
            ? payload.message
            : (payload && payload.code ? String(payload.code) : 'stream error');
        showErrorPill(truncate(msg, 60));
        scheduleReconnect();
    }

    // --- Stale timer ---
    var staleTimer = null;
    function resetStaleTimer() {
        if (staleTimer) { clearTimeout(staleTimer); }
        showStale(false);
        staleTimer = setTimeout(function () {
            showStale(true);
            setStatus('stale', 'stale');
        }, Math.max(10, refreshInterval * 2) * 1000);
    }

    // --- Paint any preview / cached payload first. ---
    if (Array.isArray(items) && items.length > 0) {
        onScoreUpdate(items[0]);
        setStatus('stale', 'cached');
    }

    // --- Resolved values, finalised once xiboIC.info() returns. ---
    var apiBaseUrl = '';
    var eventId = '';
    var url = '';

    function applyResolution(rawApiBaseUrl, rawEventId, info) {
        // apiBaseUrl: resolve display:<field>, fall back to bootstrap
        // global, strip trailing slashes.
        var resolvedApi = needsDisplayResolution(rawApiBaseUrl)
            ? resolveFromInfo(rawApiBaseUrl, info)
            : rawApiBaseUrl;
        if (!resolvedApi && typeof window !== 'undefined' && window.crowdaqBackendBase) {
            resolvedApi = String(window.crowdaqBackendBase);
        }
        resolvedApi = String(resolvedApi || '').replace(/\/+$/, '');

        // eventId: resolve display:<field>, trim.
        var resolvedEvent = needsDisplayResolution(rawEventId)
            ? resolveFromInfo(rawEventId, info)
            : rawEventId;
        resolvedEvent = String(resolvedEvent || '').trim();

        apiBaseUrl = resolvedApi;
        eventId = resolvedEvent;

        // Mirror the resolved values onto the hidden debug elements so
        // operators / headless probes can introspect what a given bar
        // actually rendered with.
        setAttr('[data-crowdaq-resolved-api-base-url]', 'data-crowdaq-resolved-api-base-url', apiBaseUrl);
        setAttr('[data-crowdaq-resolved-event-id]', 'data-crowdaq-resolved-event-id', eventId);
    }

    function isPreviewEnv() {
        if (typeof xiboIC === 'undefined') { return true; }
        try { return !!xiboIC.checkIsPreview(); }
        catch (e) { return true; }
    }

    function resolveProperties(done) {
        var needsInfo =
            needsDisplayResolution(apiBaseUrlRaw) ||
            needsDisplayResolution(eventIdRaw);

        if (!needsInfo || isPreviewEnv() || typeof xiboIC === 'undefined' || typeof xiboIC.info !== 'function') {
            // Editor / preview / no xiboIC: treat raw values as literals.
            // (In the CMS editor xiboIC.info would fail anyway; the
            // widget renders the placeholder stencil which is enough to
            // preview the layout.)
            applyResolution(apiBaseUrlRaw, eventIdRaw, null);
            done();
            return;
        }

        // Real player: mirror the canonical upstream pattern used by
        // modules/googletraffic.xml — xiboIC.info({done, error}) with a
        // JSON.parse on xhr.responseText.
        var finished = false;
        function finish(info) {
            if (finished) { return; }
            finished = true;
            applyResolution(apiBaseUrlRaw, eventIdRaw, info);
            done();
        }
        // Defensive timeout — if the local player server is wedged we
        // still want to render the placeholder instead of hanging.
        var safety = setTimeout(function () { finish(null); }, 5000);
        try {
            xiboIC.info({
                done: function (xhr) {
                    clearTimeout(safety);
                    var info = null;
                    try { info = JSON.parse(xhr.responseText); }
                    catch (e) { info = null; }
                    finish(info);
                },
                error: function () {
                    clearTimeout(safety);
                    finish(null);
                }
            });
        } catch (e) {
            clearTimeout(safety);
            finish(null);
        }
    }

    // --- Reconnect state ---
    var backoffSchedule = [1000, 2000, 5000, 15000, 30000];
    var attempt = 0;
    var MAX_ATTEMPTS = 5;
    var reconnectTimer = null;
    var source = null;
    var cleanedUp = false;

    function closeSource() {
        if (source) {
            try { source.close(); } catch (e) { /* ignore */ }
            source = null;
        }
    }
    function scheduleReconnect() {
        closeSource();
        if (cleanedUp) { return; }
        if (attempt >= MAX_ATTEMPTS) {
            setStatus('disconnected', 'offline');
            showStale(true);
            return;
        }
        var delay = backoffSchedule[Math.min(attempt, backoffSchedule.length - 1)];
        attempt += 1;
        setStatus('disconnected', 'reconnecting');
        reconnectTimer = setTimeout(openStream, delay);
    }

    function openStream() {
        if (cleanedUp) { return; }
        setStatus('connecting', 'connecting');
        try {
            source = new EventSource(url);
        } catch (err) {
            setStatus('disconnected', 'offline');
            showErrorPill('open failed');
            scheduleReconnect();
            return;
        }

        source.onopen = function () {
            attempt = 0;  // reset backoff on successful (re)connect
            setStatus('live', 'live');
            showErrorPill('');
            resetStaleTimer();
        };

        // Generic onerror: browser tried to reconnect natively; we take
        // over with bounded backoff so the widget stops thrashing after
        // MAX_ATTEMPTS.
        source.onerror = function () {
            scheduleReconnect();
        };

        function listen(name, handler) {
            source.addEventListener(name, function (msg) {
                resetStaleTimer();
                setStatus('live', 'live');
                showErrorPill('');
                var data = null;
                if (msg && typeof msg.data === 'string' && msg.data.length > 0) {
                    try { data = JSON.parse(msg.data); }
                    catch (err) { return; }
                }
                try { handler(data); } catch (err) { /* never let a handler kill the stream */ }
            });
        }

        listen('score-update', onScoreUpdate);
        listen('moment', onMoment);
        listen('status', onStatus);
        listen('heartbeat', onHeartbeat);
        listen('error', onStreamError);
    }

    // --- Cleanup on unload / widget replacement ---
    function cleanup() {
        cleanedUp = true;
        if (reconnectTimer) { clearTimeout(reconnectTimer); reconnectTimer = null; }
        if (staleTimer) { clearTimeout(staleTimer); staleTimer = null; }
        closeSource();
    }
    if (typeof window !== 'undefined' && typeof window.addEventListener === 'function') {
        window.addEventListener('beforeunload', cleanup);
        window.addEventListener('pagehide', cleanup);
    }

    // --- Post-resolution connect step. Runs after resolveProperties()
    //     has populated apiBaseUrl + eventId (either from xiboIC.info()
    //     or by falling back to the raw literal). ---
    function connect() {
        if (!apiBaseUrl) {
            showLifecycleBanner('Configure apiBaseUrl');
            setStatus('disconnected', 'not configured');
            return;
        }
        if (typeof EventSource === 'undefined') {
            setStatus('disconnected', 'no EventSource');
            showErrorPill('EventSource unsupported');
            return;
        }
        // Build stream URL. eventId is optional; when empty the backend
        // picks the best live event for the display.
        var streamEventId = eventId || 'default';
        url = apiBaseUrl + '/events/' + encodeURIComponent(streamEventId) + '/stream';
        openStream();
    }

    resolveProperties(connect);
})();
